from agno.session import Session

def detect_memory_hallucination(session: Session, agent_response: str) -> bool:
    """Detect fabricated memory recall in Agno sessions"""
    claimed_interactions = extract_claimed_history(agent_response)
    actual_history = session.chat_history

    for claimed in claimed_interactions:
        if not any(interaction.content == claimed for interaction in actual_history):
            return True
    return False

def extract_claimed_history(response: str) -> List[str]:
    """Extract claimed past interactions from agent response"""
    # Simple regex for 'in our last conversation' style references
    import re
    return re.findall(r'last.*conversation|previously discussed|you mentioned earlier', response, re.IGNORECASE)

