    """Decorator to catch structured output validation failures in Agno"""
    def wrapper(*args, **kwargs):
        try:
            result = func(*args, **kwargs)
            return result
        except ValidationError as e:
            error_details = {
                'type': 'pydantic_validation_error',
                'field_errors': e.errors(),
                'traceback': traceback.format_exc()
            }
            print(f'Structured output failed: {error_details}')
            return None
