from agno.agent import Agent
import time
from typing import Optional

def robust_multimodal_agent():
    agent = Agent(
        model='gpt-4o',
        multimodal=True,
        max_retries=3
    )

    def run_with_fallback(inputs: dict, retries: int = 0) -> str:
        try:
            if retries > 0:
                inputs['image'] = None  # Fallback to text-only
            return agent.run(**inputs)
        except Exception as e:
            if 'multimodal' in str(e).lower() and retries < 3:
                time.sleep(2 ** retries)
                return run_with_fallback(inputs, retries + 1)
            raise

    return run_with_fallback

from agno.session import Session

class GroundedMemoryAgent:
    def __init__(self, session: Session):
        self.session = session

    def grounded_chat(self, message: str) -> str:
        # Inject actual history summary into system prompt
        history_summary = self._summarize_history()
        system_prompt = f"""
You are a helpful assistant. IMPORTANT: Your conversation history is:
{history_summary}

Only reference conversations that actually occurred above. Do not fabricate past interactions.
"""

        response = self.session.agent.run(message, system=system_prompt)
        return response

    def _summarize_history(self) -> str:
        recent = self.session.chat_history[-5:]
        return '\n'.join([f"User: {m.content}" for m in recent if m.role == 'user'])

from pydantic import BaseModel, ValidationError
from agno.agent import Agent
from typing import Optional, Dict, Any

class RobustStructuredAgent:
    def __init__(self):
        self.agent = Agent(output_type=ComplexSchema)

    def safe_structured_run(self, inputs: Dict[str, Any]) -> Optional[ComplexSchema]:
        for attempt in range(3):
            try:
                raw_output = self.agent.run(**inputs)
                return ComplexSchema.model_validate(raw_output)
            except ValidationError as e:
                if attempt == 2:
                    # Return partial parse on final failure
                    return self._partial_parse(raw_output)
                # Retry with simplified schema instructions
                inputs['instructions'] += f"\nUse simple structure only. Error was: {e.errors()[:1]}"
        return None

    def _partial_parse(self, raw: Dict) -> Optional[BaseModel]:
        # Fallback to base model with optional fields
        try:
            return SimpleSchema.model_validate(raw)
        except:
            return None
